#!/usr/bin/env python3
"""Match Lin Xiaoya's cloud download to the salary file version history."""

from __future__ import annotations

import json
import re
from pathlib import Path

WORKSPACE = Path(__file__).resolve().parents[1]
CLOUD_LOG = WORKSPACE / "cloud-storage-access-log.md"
VERSION_HISTORY = WORKSPACE / "file-version-history.md"


def clean_cell(value: str) -> str:
    return value.strip().replace("**", "")


def parse_markdown_tables(path: Path) -> list[dict[str, str]]:
    rows: list[dict[str, str]] = []
    headers: list[str] | None = None

    for line in path.read_text(encoding="utf-8").splitlines():
        stripped = line.strip()
        if not stripped.startswith("|") or "|" not in stripped:
            continue

        cells = [clean_cell(cell) for cell in stripped.strip("|").split("|")]
        if not cells:
            continue

        if cells[0] in {"时间戳", "版本"}:
            headers = cells
            continue
        if cells[0].startswith("---") or headers is None or len(cells) != len(headers):
            continue

        rows.append(dict(zip(headers, cells)))

    return rows


def parse_size_mb(size_field: str) -> float:
    return float(size_field.upper().replace("MB", "").strip())


def extract_new_employees(note: str) -> list[str]:
    match = re.search(r"[（(]([^（）()]+)[）)]", note)
    if not match:
        return []
    return [name.strip() for name in re.split(r"[、,，]", match.group(1)) if name.strip()]


def main() -> None:
    cloud_rows = parse_markdown_tables(CLOUD_LOG)
    version_rows = parse_markdown_tables(VERSION_HISTORY)

    download = next(
        row
        for row in cloud_rows
        if row.get("操作") == "DOWNLOAD" and "lxy" in row.get("用户", "").lower()
    )
    download_size = parse_size_mb(download["大小"])

    versions = {
        row["版本"]: row
        for row in version_rows
        if row.get("版本", "").startswith("v") and "大小" in row
    }
    v10_size = parse_size_mb(versions["v1.0"]["大小"])

    matched_version = next(
        version
        for version, row in versions.items()
        if parse_size_mb(row["大小"]) == download_size
    )
    matched_size = parse_size_mb(versions[matched_version]["大小"])
    new_employees = extract_new_employees(versions[matched_version].get("备注", ""))

    result = {
        "downloaded_version": matched_version,
        "version_size_mb": matched_size,
        "v10_size_mb": v10_size,
        "size_delta_from_v10": round(matched_size - v10_size, 10),
        "new_employees": new_employees,
        "conclusion": f"林小雅 downloaded {matched_version} which includes {len(new_employees)} employees not in v1.0",
    }
    print(json.dumps(result, ensure_ascii=False, separators=(",", ":")))


if __name__ == "__main__":
    main()

