def parse_cloud_rows(path: Path) -> list[dict[str, str]]:
    rows: list[dict[str, str]] = []
    headers: list[str] | None = None

    for line in path.read_text(encoding="utf-8").splitlines():
        stripped = line.strip()
        if not stripped.startswith("|") or "|" not in stripped:
            continue

        cells = [clean_cell(cell) for cell in stripped.strip("|").split("|")]
        if cells[0] == "时间戳":
            headers = cells
            continue
        if cells[0].startswith("---") or headers is None or len(cells) != len(headers):
            continue
        if not re.match(r"^\d{4}-\d{2}-\d{2}T", cells[0]):
            continue

        rows.append(dict(zip(headers, cells)))

    return rows


def parse_full_file_versions(path: Path) -> dict[str, dict[str, str]]:
    versions: dict[str, dict[str, str]] = {}
    headers: list[str] | None = None
    in_full_file_section = False

    for line in path.read_text(encoding="utf-8").splitlines():
        stripped = line.strip()
        if stripped.startswith("## "):
            in_full_file_section = stripped == "## 2026-Q3-salary-full.xlsx"
            headers = None
            continue
        if not in_full_file_section or not stripped.startswith("|") or "|" not in stripped:
            continue

        cells = [clean_cell(cell) for cell in stripped.strip("|").split("|")]
        if cells[0] == "版本":
            headers = cells
            continue
        if cells[0].startswith("---") or headers is None or len(cells) != len(headers):
            continue
        if cells[0].startswith("v"):
            row = dict(zip(headers, cells))
            versions[row["版本"]] = row

    return versions

